import{_ as t,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as n,o as s,c,a2 as l}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"en/Other/ocr.md","filePath":"en/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"en/Other/ocr.md"};function h(u,e,g,m,f,y){return s(),c("div",null,[...e[0]||(e[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR extracts text from images, scans, and document screenshots.</p><p>After recognition, you can copy the result, export it as <code>Markdown</code>, <code>PDF</code>, or <code>Word</code>, or package multiple formats together for download.</p><h2 id="what-ocr-can-do" tabindex="-1">What OCR Can Do <a class="header-anchor" href="#what-ocr-can-do" aria-label="Permalink to &quot;What OCR Can Do&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>Extracts text from images, screenshots, and scans.</td></tr><tr><td>Document layout recognition</td><td>Better for tables, formulas, stamps, and mixed text-image layouts.</td></tr><tr><td>Multiple services</td><td>Supports Baidu PaddleOCR, Microsoft Azure Vision, and Google Vision.</td></tr><tr><td>Copy results</td><td>Copy recognized text after processing.</td></tr><tr><td>Export files</td><td>Export <code>Markdown</code>, <code>PDF</code>, and <code>Word</code>.</td></tr><tr><td>Batch packaging</td><td>After recognizing multiple files, download results as a package.</td></tr></tbody></table><h2 id="configure-ocr-services-first" tabindex="-1">Configure OCR Services First <a class="header-anchor" href="#configure-ocr-services-first" aria-label="Permalink to &quot;Configure OCR Services First&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="IP geolocation and OCR" loading="lazy"></p><p>Fill in credentials for the services you want to use:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Recommended first choice. Good for documents, images, tables, and mixed layouts.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> and <code>Azure Vision API Key</code></td><td>Useful if you already use Microsoft cloud services.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> is only used for quota query.</td><td>Useful if you use Google Cloud services.</td></tr></tbody></table><p>Save after filling in credentials.</p><p>You can configure only one service for initial testing. You do not need all three.</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup has two parts:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>Use OCR</td><td>Enable <code>Cloud Vision API</code>, then create an <code>API Key</code>.</td></tr><tr><td>Query usage</td><td>Create a service account, grant <code>Monitoring Viewer</code>, then download the service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="use-google-for-ocr" tabindex="-1">Use Google for OCR <a class="header-anchor" href="#use-google-for-ocr" aria-label="Permalink to &quot;Use Google for OCR&quot;">​</a></h3><ol><li>Open Google Cloud Console.</li><li>Go to <code>APIs &amp; Services</code>.</li><li>Open <code>Library</code>, search for <code>Cloud Vision API</code>, and enable it.</li><li>Return to <code>Credentials</code>.</li><li>Create an <code>API Key</code>.</li><li>Open the API Key and copy it.</li><li>Paste it into <code>Google Vision API Key</code> in ImgBed.</li><li>Save.</li></ol><p>You can then choose Google Vision in the OCR dialog.</p><h3 id="query-google-usage" tabindex="-1">Query Google Usage <a class="header-anchor" href="#query-google-usage" aria-label="Permalink to &quot;Query Google Usage&quot;">​</a></h3><p>Quota query is not required for recognition.</p><p>It only shows roughly how many Google Vision calls were used in the last 30 days.</p><ol><li>In Google Cloud Console, open <code>IAM &amp; Admin</code>.</li><li>Open <code>Service Accounts</code>.</li><li>Create a service account, such as <code>vision-monitor</code>.</li><li>Grant it the <code>Monitoring Viewer</code> role.</li><li>Open the service account details and create a key.</li><li>Choose <code>JSON</code>.</li><li>Download the generated JSON file.</li><li>Return to ImgBed and import it under service account <code>JSON</code> (optional).</li><li>After import succeeds, click quota query.</li></ol><p>After import, ImgBed shows the project name that owns the service account. When querying usage, ImgBed reads Google monitoring data and shows this month&#39;s call count.</p><p>In short:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Performs OCR recognition.</td></tr><tr><td>Service account <code>JSON</code></td><td>Queries how many Google Vision calls were used.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>Allows the service account to read usage data.</td></tr></tbody></table><h2 id="get-a-baidu-paddleocr-token" tabindex="-1">Get a Baidu PaddleOCR Token <a class="header-anchor" href="#get-a-baidu-paddleocr-token" aria-label="Permalink to &quot;Get a Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR requires an access token.</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Open the <code>API</code> call window on the Baidu PaddleOCR page, click to get a token, then copy it.</p><p>Return to ImgBed, paste it into <code>PaddleOCR Token</code>, and save.</p><h2 id="start-recognition" tabindex="-1">Start Recognition <a class="header-anchor" href="#start-recognition" aria-label="Permalink to &quot;Start Recognition&quot;">​</a></h2><p>In File Management, select an image or document screenshot and click <code>OCR</code>.</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>In the dialog, choose the recognition service and model.</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Recommended default. Good for documents, tables, formulas, stamps, and mixed layouts.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Simple images, ordinary text, and lightweight recognition.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Multilingual, complex images, and chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>More complex document pages and layout recovery.</td></tr></tbody></table><p>If you are unsure, start with <code>PP-StructureV3</code>.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Use when the image is rotated or skewed.</td></tr><tr><td>Document flattening</td><td>Use for photographed documents with curvature or tilt.</td></tr><tr><td>Layout detection</td><td>Use when you want to preserve headings, paragraphs, tables, and image structure.</td></tr><tr><td>Chart recognition</td><td>Use when the image contains charts or complex structures.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Makes exported Markdown easier to read.</td></tr></tbody></table><p>For regular screenshots, keep options minimal. For document scans, enable more document-related options.</p><h2 id="view-results" tabindex="-1">View Results <a class="header-anchor" href="#view-results" aria-label="Permalink to &quot;View Results&quot;">​</a></h2><p>After recognition finishes, the dialog shows the result.</p><p>You can copy it directly or choose export formats.</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>For document pages, exported <code>PDF</code> can preserve page appearance while keeping text searchable. This is useful for archiving scans and finding content later.</p><h2 id="choosing-an-export-format" tabindex="-1">Choosing an Export Format <a class="header-anchor" href="#choosing-an-export-format" aria-label="Permalink to &quot;Choosing an Export Format&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notes, documentation systems, and later editing.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Preserving page appearance and scanned document results.</td></tr><tr><td><code>Word (.docx)</code></td><td>Continued layout editing, text modification, and handoff to others.</td></tr><tr><td>Export all</td><td>Saves multiple formats and the original image, suitable for important archives.</td></tr></tbody></table><p>If you only need text, export Markdown.</p><p>If you need page appearance, use PDF or Word.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Exported Word documents can be opened and edited with office software.</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>Some documents include recognized images, headings, and paragraphs in the Word output.</p><p>Recognition quality depends on original image clarity, model choice, and document complexity.</p><h2 id="best-file-types-for-ocr" tabindex="-1">Best File Types for OCR <a class="header-anchor" href="#best-file-types-for-ocr" aria-label="Permalink to &quot;Best File Types for OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>Recognize directly.</td></tr><tr><td>Scans</td><td>Prefer <code>PP-StructureV3</code>.</td></tr><tr><td>Photographed documents</td><td>Enable orientation correction and document flattening.</td></tr><tr><td>Tables, formulas, stamps</td><td>Prefer structured models.</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> is usually enough.</td></tr></tbody></table><p>Clearer images with straighter text usually produce better results.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>Check that the service token or key has been saved.</td></tr><tr><td>Recognition is slow</td><td>Complex documents and large images take longer.</td></tr><tr><td>Table is incomplete</td><td>Try a structured model.</td></tr><tr><td>Text has mistakes</td><td>Blur, glare, and skew increase recognition errors. Try a clearer image.</td></tr><tr><td>Word output contains many images</td><td>Structured models may preserve some recognized images. This is normal.</td></tr></tbody></table><h3 id="google-quota-query-fails" tabindex="-1">Google Quota Query Fails <a class="header-anchor" href="#google-quota-query-fails" aria-label="Permalink to &quot;Google Quota Query Fails&quot;">​</a></h3><p>Check:</p><ol><li>Service account <code>JSON</code> has been imported.</li><li>The service account has the <code>Monitoring Viewer</code> role.</li><li><code>Cloud Vision API</code> is enabled for the project.</li></ol><p>If you only need OCR and not usage query, you can ignore the service account JSON and only fill in <code>Google Vision API Key</code>.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open System Settings</span></span>
<span class="line"><span>-&gt; Open Other Settings</span></span>
<span class="line"><span>-&gt; Fill OCR service credentials</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Return to File Management</span></span>
<span class="line"><span>-&gt; Select a file and click OCR</span></span>
<span class="line"><span>-&gt; Choose a model</span></span>
<span class="line"><span>-&gt; Wait for recognition</span></span>
<span class="line"><span>-&gt; Copy results or export Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const k=n(p,[["render",h]]);export{P as __pageData,k as default};
